class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int res = 0, zeros = 0, ones = 0;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '0') zeros++;
            else ones++;
            if (zeros == ones) res = max(res, zeros * 2);
            else if (zeros > ones) zeros = 0, ones = 0;
        }
        return res;
    }
};
